mapper.select:
select p.*, p.`condition`, u.username
from product p,user u
where p.uid=u.id and p.id = #{value};

select p.* from product p join sc s on p.sid = s.id join fc f on s.fcid = f.id where p.status=1 and s.fcid=#{id}
and p.name like concat('%',#{searchText},'%')
and s.id in
#{item}
and p.currentprice BETWEEN #{priceInterval.min} and #{priceInterval.max}
and p.creattime >= DATE_SUB(CURDATE(),INTERVAL #{timeInterval} DAY)

mapper.insert:
insert into product (
name, details, images, clicks, creattime, originalprice, currentprice, deal, `condition`, address, comments, sid, uid
) values (
#{name}, #{details}, #{images}, #{clicks}, #{creattime}, #{originalprice}, #{currentprice}, #{deal}, #{condition}, #{address}, #{comments}, #{sid}, #{uid}
)

mapper.update:
update product
clicks = clicks + 1, name=#{name}, sid=#{sid}, currentprice=#{currentprice}, originalprice=#{originalprice}, deal=#{deal}, `condition`=#{condition}, address=#{address}, details=#{details}, images=#{images}, comments=#{comments}, status=#{status},
where id=#{id}
